// Force Disposition matchup analysis, sourced from Tabletop Battles' 11th-edition
// Force Disposition reviews (one article per Disposition). Each article rates all
// five of that Disposition's missions 1–5 (how well IT fares against each opponent
// Disposition) and breaks down the scoring and tactics; those ratings are
// DIRECTIONAL — the value for (you, faced) is scored from `you`'s point of view, so
// it does not necessarily mirror (faced, you). Averages are computed from the five
// ratings. Prose is condensed from the reviews (see `reviewUrl`); regenerate from
// the source articles. Bullet lines start with '• ' and render as lists.

import type { DispositionKey } from './dispositions'

/** How one Disposition fares in a single matchup, from its own perspective. */
export interface MatchupAnalysis {
  /** The opponent Disposition being faced. */
  faced: DispositionKey
  /** Source's 1–5 rating (5 = strongly favours `you`; 1 = strongly against). */
  rating: number
  /** One-paragraph verdict — the overall read on the matchup. */
  verdict: string
  /** How you score your Primary Mission (scoring conditions + a sample curve). */
  scoreYou: string
  /** How your opponent scores theirs. */
  scoreOpponent: string
  /** Tips for playing offensively into this matchup. */
  offense: string
  /** Tips for defending this matchup. */
  defense: string
  /** Listbuilding notes, where the review gives them. */
  listbuilding?: string
}

/** A Disposition's full review: its five matchups and their average rating. */
export interface DispositionAnalysis {
  you: DispositionKey
  /** Source article URL for attribution / deep reading. */
  reviewUrl: string
  /** Mean of the five matchup ratings, to one decimal. */
  average: number
  matchups: MatchupAnalysis[]
}

